#include <bits/stdc++.h>
using namespace std;
int t,n,a[100005];
bool to[100005];
vector<int> g[100005];
int dfs(int x){
    to[x]=1;
    int flag=0,len=g[x].size();
    for(int i=0;i<len;i++)
        if(!to[g[x][i]]){
            int val=dfs(g[x][i]);
            if(val==3)
                return 3;
            else if(val==2)
                if(flag>0)
                    return 3;
                else
                    flag=2;
            else if(val==1)
                if(flag==2)
                    return 3;
                else
                    flag=flag+1;
        }
    if(flag==0 && a[x])
        flag=1;
    return flag;
}
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d",&a[i]);
            g[i].clear();
        }
        memset(to,false,sizeof(to));
        for(int i=1;i<n;i++){
            int u,v;
            scanf("%d%d",&u,&v);
            g[u].push_back(v);
            g[v].push_back(u);
        }
        if(dfs(1)==3)
            printf("No\n");
        else
            printf("Yes\n");
    }
    return 0;
}
